/* --- LR 总控程序 --- */
int yyparse(void) {
    /* 栈定义 */
    #define STACK_SIZE 1024
    int state_stack[STACK_SIZE];
    int sym_stack[STACK_SIZE];
    YYSTYPE val_stack[STACK_SIZE];
    int sp = 0; // 栈指针

    /* 初始化 */
    state_stack[sp] = 0; // 初始状态 0
    sym_stack[sp] = 0;   // 初始符号 $
    sp++;

    int token = yylex(); // 读取第一个 Token

    /* 主循环 */
    while (1) {
        int cur_state = state_stack[sp - 1];
        int act_type = action_table[cur_state][token][0];
        int act_num = action_table[cur_state][token][1];

        switch (act_type) {
            case ACTION_SHIFT: /* 移进 */
                state_stack[sp] = act_num;
                sym_stack[sp] = token;
                val_stack[sp] = yylval;
                sp++;
                token = yylex();
                break;

            case ACTION_REDUCE: /* 归约 */
                {
                    int prod_id = act_num;
                    int left_idx = prod_info[prod_id][0];
                    int right_len = prod_info[prod_id][1];

                    /* 弹出栈 */
                    sp -= right_len;

                    /* 这里插入语义动作（课程设计可扩展） */
                    /* $$ = ...; */

                    /* 查 Goto 表 */
                    int prev_state = state_stack[sp - 1];
                    int next_state = goto_table[prev_state][left_idx];

                    /* 压入新状态和非终结符 */
                    state_stack[sp] = next_state;
                    sym_stack[sp] = left_idx + 1000;
                    /* val_stack[sp] = ...; */
                    sp++;
                }
                break;

            case ACTION_ACCEPT: /* 接受 */
                return 0; /* 成功 */

            case ACTION_ERROR: /* 错误 */
            default:
                yyerror("语法错误");
                return 1; /* 失败 */
        }
    }
}

/* --- 错误处理函数 --- */
void yyerror(const char* msg) {
    fprintf(stderr, "[语法错误] 行号: %d, 信息: %s, 当前Token: %s\n",
            yylineno, msg, yytext);
}

