/* ========== 错误处理函数 ========== */
void yyerror(const char* s) {
    fprintf(stderr, "[语法错误] 行号:%d, 错误信息:%s, 当前Token:%s\n", 
            yylineno, s, yytext);
}

/* ========== 主函数 ========== */
int main(int argc, char* argv[]) {
    printf("===== MiniC 语法分析器启动 =====\n\n");
    // 开启调试模式（可选）
    // yydebug = 1;
    int ret = yyparse();
    printf("\n===== 语法分析结束 =====\n");
    if (ret == 0) {
        printf("✅ 解析成功：无语法错误\n");
    } else {
        printf("❌ 解析失败：存在语法错误\n");
    }
    return ret;
}

